import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { discordChannel } from "eve/channels/discord";

export default discordChannel({
  botToken: () => process.env.DISCORD_BOT_TOKEN!,
  publicKey: () => process.env.DISCORD_PUBLIC_KEY!,
});

import { connectSlackCredentials } from "@vercel/connect/eve";
import { slackChannel } from "eve/channels/slack";

export default slackChannel({
  credentials: connectSlackCredentials("slack/developer-community-manager"),
});

import { connect } from "@vercel/connect/eve";
import { defineMcpClientConnection } from "eve/connections";

// App-scoped so schedules can use this connection without a user principal.
export default defineMcpClientConnection({
  url: "https://mcp.notion.com/mcp",
  description: "Notion workspace: search and edit pages and databases.",
  auth: connect({ connector: "notion", principalType: "app" }),
});

import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export type SignalRecord = {
  theme: string;
  evidence: string;
  frequency: "once" | "recurring" | "widespread";
  loggedAt: string;
};

const STORE_PATH = path.join(process.cwd(), "var", "signals.json");

export async function saveSignal(record: SignalRecord): Promise<SignalRecord> {
  let all: SignalRecord[] = [];
  try {
    all = JSON.parse(await readFile(STORE_PATH, "utf-8")) as SignalRecord[];
  } catch {
    all = [];
  }
  all.push(record);
  await mkdir(path.dirname(STORE_PATH), { recursive: true });
  await writeFile(STORE_PATH, `${JSON.stringify(all, null, 2)}\n`, "utf-8");
  return record;
}

import { defineAgent } from "eve";

export default defineAgent({
  description:
    "Turn a community bug report into a minimal reproduction: environment, steps, expected vs actual, and a short title. Return structured repro notes the parent can escalate.",
  model: "openai/gpt-5.4-mini",
});

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

export default defineTool({
  description:
    "Escalate a community-reported bug with reproduction steps. Approval-gated before writing to bugs/.",
  inputSchema: z.object({
    title: z.string().min(1),
    markdown: z.string().min(1),
  }),
  approval: always(),
  async execute({ title, markdown }, ctx) {
    const sandbox = await ctx.getSandbox();
    const slug = title.toLowerCase().replaceAll(/[^a-z0-9]+/g, "-");
    const bugPath = `bugs/${slug}.md`;
    await sandbox.writeTextFile({ path: bugPath, content: markdown });
    return { escalated: true, path: bugPath };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { saveSignal } from "../lib/signal-store";

export default defineTool({
  description: "Log a recurring community pain point as roadmap signal.",
  inputSchema: z.object({
    theme: z.string().min(1),
    evidence: z.string().min(1),
    frequency: z.enum(["once", "recurring", "widespread"]),
  }),
  async execute(input) {
    const record = await saveSignal({
      ...input,
      loggedAt: new Date().toISOString(),
    });
    return { saved: true, record };
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Escalating a bug parks on approval.",
  async test(t) {
    await t.send(
      'Escalate this bug immediately: title "Webhook retries infinite", body "Steps: fire webhook; loops 50x."'
    );
    t.parked();
    t.calledTool("escalate_bug", { status: "pending", count: 1 });
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 2,
  timeoutMs: 180_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Logging roadmap signal persists the theme.",
  async test(t) {
    await t.send(
      'Log roadmap signal theme "better webhook docs", frequency recurring, evidence: 4 Discord threads this week.'
    );
    t.succeeded();
    t.calledTool("log_roadmap_signal", {
      input: { theme: /webhook/i, frequency: "recurring" },
    });
  },
});

